    /** 2030 futuristic — visionary ending */
    export function drawFuturisticScene(bg: Image): void {
        bg.fill(12)
        bg.setPixel(10, 5, 1)
        bg.setPixel(30, 12, 1)
        bg.setPixel(55, 3, 1)
        bg.setPixel(80, 8, 1)
        bg.setPixel(110, 6, 1)
        bg.setPixel(140, 11, 1)
        bg.setPixel(25, 18, 1)
        bg.setPixel(95, 2, 1)
        bg.setPixel(150, 16, 1)
        bg.fillRect(10, 20, 16, 70, 10)
        for (let y = 24; y < 88; y += 8) {
            bg.fillRect(13, y, 4, 3, 5)
            bg.fillRect(19, y, 4, 3, 5)
        }
        bg.fillRect(30, 40, 20, 50, 8)
        for (let y = 44; y < 88; y += 8) {
            bg.fillRect(33, y, 5, 3, 9)
            bg.fillRect(42, y, 5, 3, 9)
        }
        bg.fillRect(55, 15, 24, 75, 10)
        bg.fillRect(60, 12, 14, 6, 5)
        for (let y = 22; y < 88; y += 6) {
            bg.fillRect(58, y, 6, 2, 9)
            bg.fillRect(66, y, 6, 2, 9)
        }
        bg.fillRect(85, 50, 30, 40, 8)
        for (let y = 54; y < 88; y += 8) {
            bg.fillRect(88, y, 6, 4, 5)
            bg.fillRect(98, y, 6, 4, 5)
        }
        bg.fillRect(120, 25, 18, 65, 10)
        for (let y = 30; y < 88; y += 7) {
            bg.fillRect(123, y, 5, 3, 5)
            bg.fillRect(131, y, 4, 3, 9)
        }
        bg.fillRect(142, 35, 18, 55, 8)
        for (let y = 39; y < 88; y += 8) {
            bg.fillRect(145, y, 4, 3, 5)
            bg.fillRect(152, y, 4, 3, 9)
        }
        bg.fillRect(0, 90, 160, 30, 15)
        bg.drawLine(0, 90, 159, 90, 10)
        bg.drawLine(0, 92, 159, 92, 5)
        bg.fillRect(40, 96, 80, 12, 12)
        bg.drawRect(39, 95, 82, 14, 9)
        bg.print("GAME JAM 2030", 43, 99, 5)
    }
